Use MSTest's `[DataTestMethod]` with `[DataRow]` to parameterize. This collapses 9 methods into 2:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Validation.Tests;

[TestClass]
public sealed class InputValidatorTests
{
    [DataTestMethod]
    [DataRow("", false, "Input cannot be empty", DisplayName = "Empty string")]
    [DataRow(null, false, "Input cannot be empty", DisplayName = "Null")]
    [DataRow("   ", false, "Input cannot be empty", DisplayName = "Whitespace only")]
    [DataRow("ab", false, "Input must be at least 3 characters", DisplayName = "Too short")]
    [DataRow("hello<script>", false, "Input contains invalid characters", DisplayName = "Special chars")]
    [DataRow("hello-world", true, null, DisplayName = "Valid input")]
    [DataRow("abc", true, null, DisplayName = "Min length boundary")]
    public void Validate_ReturnsExpectedResult(
        string? input, bool expectedIsValid, string? expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.AreEqual(expectedIsValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    // DataRow requires compile-time constants, so computed strings
    // use DynamicData instead.
    [DataTestMethod]
    [DynamicData(nameof(LengthBoundaryCases), DynamicDataSourceType.Method)]
    public void Validate_LengthBoundaries_ReturnsExpectedResult(
        string input, bool expectedIsValid, string? expectedError)
    {
        var validator = new InputValidator();
        var result = validator.Validate(input);
        Assert.AreEqual(expectedIsValid, result.IsValid);
        Assert.AreEqual(expectedError, result.ErrorMessage);
    }

    private static IEnumerable<object?[]> LengthBoundaryCases()
    {
        yield return [new string('a', 255), true, null];
        yield return [new string('x', 256), false, "Input must not exceed 255 characters"];
    }
}
```

**Key changes:**
- **`[DataRow]`** — each case is one attribute line; adding a new case is a one-liner
- **`[DynamicData]`** — handles the computed-string cases that `DataRow` can't (it requires compile-time constants)
- **`DisplayName`** — gives readable names in test output instead of raw parameter values
